#include<cstdio>
#include<queue>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;
int dis[N][20],d[N<<1],n,m;
vector<int> G[N][2],B[N<<1];
deque<int> deq;
inline void bfs01()
{
	memset(d,0x3f,sizeof(d));d[1]=0;
	deq.push_back(1);while(!deq.empty())
	{
		int u=deq.front();deq.pop_front();
		for(int v:B[u])
		{
			if(v>>30&1)
			{
				if(d[u]+1<d[v^(1<<30)])
				{
					d[v^(1<<30)]=d[u]+1;
					deq.push_back(v^(1<<30));
				}
			}
			else
			{
				if(d[u]<d[v])
				{
					d[v]=d[u];
					deq.push_front(v);
				}
			}
		}
	}
}
struct nd{int u,i;}que[N*20];int H,T;
inline void bfs()
{
	memset(dis,0x3f,sizeof(dis));
	dis[1][0]=0;que[H=T=0]={1,0};
	while(H<=T)
	{
		nd u=que[H++];
		for(int v:G[u.u][u.i&1])
		{
			if(u.i-d[v]>=20)continue;
			if(dis[u.u][u.i-d[u.u]]+1<dis[v][u.i-d[v]])
			{
				dis[v][u.i-d[v]]=dis[u.u][u.i-d[u.u]]+1;
				que[++T]={v,u.i};
			}
		}
		for(int v:G[u.u][(u.i&1)^1])
		{
			if(u.i+1-d[v]>=20)continue;
			if(dis[u.u][u.i-d[u.u]]+1<dis[v][u.i+1-d[v]])
			{
				dis[v][u.i+1-d[v]]=dis[u.u][u.i-d[u.u]]+1;
				que[++T]={v,u.i+1};
			}
		}
	}
}
const int Mod=998244353;
inline int qpow(int a,int b)
{
	if(b==-1)return 0;
	int r(1);for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)r=1ll*r*a%Mod;return r;
}
int main()
{
	n=read();m=read();rep(1,m,i)
	{
		int u=read(),v=read();
		G[u][0].push_back(v);
		G[v][1].push_back(u);
		B[u].push_back(v);
		B[v+n].push_back(u+n);
	}
	rep(1,n,i)
	{
		B[i].push_back((i+n)|(1<<30));
		B[i+n].push_back((i)|(1<<30));
	}
	bfs01();rep(1,n,i)d[i]=min(d[i],d[i+n]);
//	rep(1,n,i)printf("%d ",d[i]);puts("");
	bfs();int mnk=d[n],mnv=dis[n][0];
//	printf("cnm :: %d %d\n",dis[n][1],d[n]);
	rep(1,19,i)
	{
		if(d[n]+i>=20)break;
		if(dis[n][i]+(1<<(d[n]+i))<mnv+(1<<mnk)){mnk=d[n]+i;mnv=dis[n][i];}
//		printf("QAQ :: %d (%d,%d) %d %d\n",i,mnk,mnv,dis[n][i],dis[n][i]);
	}
	printf("%lld\n",(0ll+qpow(2,mnk)+mnv-1+Mod)%Mod);
}
